    boolean handleMessage(int what, Object data) {
        switch(what){
        case MESSAGE_GET_COUNTERS:
            getCounters();
            return true;
        case MESSAGE_DELETE_COUNTER:
            deleteCounter((Integer)data);
            getCounters();
            return true;
        case MESSAGE_INCREMENT_COUNTER:
            changeCount(1, (CounterVo)data);
            getCounters();
            return true;
