:::java
protected final void notifyOutboxHandlers(int what, int arg1, int arg2, Object obj) {
    if (!outboxHandlers.isEmpty()) {
        for (Handler handler : outboxHandlers) {
            Message msg = Message.obtain(handler, what, arg1, arg2, obj);
            msg.sendToTarget();
        }
    }
}

